INSERT INTO `BMS_ARTICLE` (`ID`, `TITLE`, `SUMMARY`, `CONTENT`, `COVER_IMAGE`, `CATEGORY_ID`, `AUTHOR_ID`, `STATUS`, `VIEW_COUNT`, `LIKE_COUNT`, `COMMENT_COUNT`, `IS_TOP`, `IS_RECOMMEND`, `ALLOW_COMMENT`, `PUBLISH_TIME`, `SORT_CODE`, `DELETE_FLAG`, `CREATE_TIME`, `CREATE_USER`) VALUES
('1820000000000000001', 'Spring Boot 3.0 新特性详解', '本文详细介绍Spring Boot 3.0的新特性，包括对Java 17的支持、原生编译、可观测性增强等。', '<h1>Spring Boot 3.0 新特性详解</h1><p>Spring Boot 3.0 是一个重要的里程碑版本，带来了许多令人兴奋的新特性...</p>', NULL, '1800000000000000001', '1570687866138206208', 'PUBLISHED', 1256, 89, 12, 1, 1, 1, NOW(), 1, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000002', 'Vue 3 组合式API最佳实践', '深入探讨Vue 3组合式API的使用技巧和最佳实践，帮助你编写更优雅的代码。', '<h1>Vue 3 组合式API最佳实践</h1><p>Vue 3 引入了组合式API，这是一种全新的组件逻辑组织方式...</p>', NULL, '1800000000000000001', '1570687866138206208', 'PUBLISHED', 892, 67, 8, 0, 1, 1, NOW(), 2, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000003', 'Docker容器化部署实战', '从零开始学习Docker，掌握容器化部署的核心技能，提升开发效率。', '<h1>Docker容器化部署实战</h1><p>Docker已经成为现代软件开发不可或缺的工具...</p>', NULL, '1800000000000000003', '1570687866138206208', 'PUBLISHED', 654, 45, 5, 0, 0, 1, NOW(), 3, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000004', 'MySQL性能优化指南', '全面的MySQL性能优化策略，从索引设计到查询优化，助你打造高性能数据库。', '<h1>MySQL性能优化指南</h1><p>数据库性能优化是后端开发的重要技能...</p>', NULL, '1800000000000000001', '1570687866138206208', 'PUBLISHED', 1123, 78, 15, 0, 1, 1, NOW(), 4, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000005', 'Redis缓存策略深度解析', '深入理解Redis的缓存策略，掌握缓存穿透、击穿、雪崩的解决方案。', '<h1>Redis缓存策略深度解析</h1><p>Redis作为高性能缓存中间件，在现代架构中扮演着重要角色...</p>', NULL, '1800000000000000001', '1570687866138206208', 'PUBLISHED', 789, 56, 9, 0, 0, 1, NOW(), 5, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000006', '程序员的自我修养', '分享程序员职业发展的思考，从技术成长到团队协作的心得体会。', '<h1>程序员的自我修养</h1><p>作为一名程序员，除了技术能力，还有很多方面需要修炼...</p>', NULL, '1800000000000000002', '1570687866138206208', 'PUBLISHED', 456, 34, 6, 0, 0, 1, NOW(), 6, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000007', '微服务架构设计模式', '系统介绍微服务架构的设计模式，帮助你在分布式系统中做出正确的技术选型。', '<h1>微服务架构设计模式</h1><p>微服务架构已经成为企业级应用的主流架构风格...</p>', NULL, '1800000000000000003', '1570687866138206208', 'PUBLISHED', 567, 42, 7, 0, 1, 1, NOW(), 7, 'NOT_DELETE', NOW(), '1570687866138206208'),
('1820000000000000008', '《代码整洁之道》读书笔记', '阅读Robert C. Martin的经典著作后的思考与实践总结。', '<h1>《代码整洁之道》读书笔记</h1><p>这本书是每个程序员必读的经典...</p>', NULL, '1800000000000000004', '1570687866138206208', 'PUBLISHED', 321, 28, 4, 0, 0, 1, NOW(), 8, 'NOT_DELETE', NOW(), '1570687866138206208');
